# Convert frames to FrameBuffer
frame_buffers = [framebuf.FrameBuffer(bytearray(frame), FRAME_WIDTH, FRAME_HEIGHT, framebuf.MONO_HLSB) for frame in frames]

# Main loop
frame_index = 0
while True:
    oled.fill(0)
    oled.blit(frame_buffers[frame_index], 32, 0)
    oled.show()
    frame_index = (frame_index + 1) % len(frames)
    time.sleep_ms(FRAME_DELAY)

